import React, {useEffect} from 'react'
import jwt_decode from 'jwt-decode'
import {useSelector, useDispatch} from 'react-redux'
import {accountSelector, handleLogin, handleLogout, openLoginForm} from '../redux/accountSlice'


export default function GoogleLoginBtn () {
	const account = useSelector(accountSelector)
	const dispatch = useDispatch()

	useEffect(() => {
		/*global google*/
		function handleCredentialResponse(response) {
			const user = jwt_decode(response.credential)

			console.log(user)
			dispatch(handleLogin())
			//dispatch(openLoginForm())

		  }
		google.accounts.id.initialize({
			client_id: '567926913321-oofmqdtjvc13bvnlsviubhdrpkuma4vm.apps.googleusercontent.com',
			callback: handleCredentialResponse
		});
		google.accounts.id.renderButton(
			document.getElementById('buttonDiv'),
			{ theme: 'outline', size: 'large' , width:'308px', text:'continue_with', locale: "en_US"} 
		);
		//google.accounts.id.prompt();

	}, [])

	console.log(account.isLogin)

	return (
		<div id='buttonDiv'></div>
	)
}
